// 1. Pega a data do outro node
const data = $('Disponibilidade_Formatada_Final').item.json.dia_final;

// 2. Pega a string de horários bruta
const resultadoBruto = items[0].json.resultado;

// 3. Transforma em array, limpa espaços e ordena cronologicamente
const horariosOrdenados = resultadoBruto
  .split(',')
  .map(h => h.trim())
  .sort((a, b) => {
    const [hA, mA] = a.split(':').map(Number);
    const [hB, mB] = b.split(':').map(Number);
    return (hA * 60 + mA) - (hB * 60 + mB);
  });

// 4. Separa os horários em baldes (buckets) por período
let manha = [];
let tarde = [];
let noite = [];

horariosOrdenados.forEach(horario => {
  const hora = parseInt(horario.split(':')[0]);

  if (hora < 12) {
    manha.push(horario);
  } else if (hora >= 12 && hora <= 17) {
    tarde.push(horario);
  } else {
    noite.push(horario);
  }
});

// 5. Monta a string bonitinha e formatada
let partes = [];
if (manha.length > 0) partes.push(`☀️ *Manhã:* ${manha.join(', ')}`);
if (tarde.length > 0) partes.push(`🌤️ *Tarde:* ${tarde.join(', ')}`);
if (noite.length > 0) partes.push(`🌙 *Noite:* ${noite.join(', ')}`);

const resultadoFormatado = partes.join('\n');

// 6. Retorna para o n8n
return [
  {
    json: {
      data,
      resultado: resultadoFormatado, // Texto bonito para o usuário
      raw_list: horariosOrdenados // Lista pura caso a IA precise processar
    }
  }
];

